def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    component = ((ratio - a) ** 6) / ((a + b)**2 + 1) * np.sin(ratio * b / (a + 2))
                    priority += component * ((-1) ** (a + b))
            priority += np.exp(ratio - 8) * (np.sin(ratio * 1.3) + np.cos(ratio * 0.7)) ** 2
        elif 5 < ratio <= 8:
            total = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                inner_sum = 0
                for q in range(1, p + 4):
                    factor = ((ratio - p) ** 4) * np.cos(ratio * q * 0.9) / (q * 1.2 + 0.7)
                    inner_sum += np.tanh(factor) * (q / (p + 0.5))
                total += inner_sum / (p + 1)
            priority = total + np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3.5
        elif 2 <= ratio <= 5:
            summation = 0
            for r in range(1, 15):
                power_term = ((ratio - 2) ** r) / (r ** 1.5)
                trig_term = np.cos(r * 1.4 * ratio) * np.sin(r * 0.7 * i)
                summation += power_term * trig_term
            priority = (summation * np.sin(5 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (5 - ratio)) * 2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.exp(-n * ratio / 5)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 8):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1) ** m) / (m * 0.7)
        elif 0.5 <= ratio < 1:
            s = 0
            for u in range(1, 18):
                s += ((1 - ratio) ** u) / (u * 5) * np.cos(u * ratio * 1.3)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for v in range(1, 7):
                priority += ((1 - ratio) ** v) * np.sin(v * item * 1.5) * 1.1
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 14):
                s += ((0.5 - ratio) ** w) / (w * 4.5) * np.cos(w * ratio * 2.1)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.4) * 3.5
            for z in range(1, 9):
                priority += ((0.5 - ratio) ** z) / (z * 7) * np.cos(item * z * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1) * ((-1) ** t)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for x in range(1, 10):
                priority += ((0.2 - ratio) ** x) / (x * 8) * np.cos(item * x * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 5 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * int(item * 1.1)) % 7 == 0:
            priority += np.sin(i * ratio * item) * 0.5
        else:
            priority -= np.cos(i * ratio * item) * 0.5
        priorities[i] = priority
    return priorities
